def _sage_maker_model_to_nested(
    sage_maker_model: SageMakerModel,
) -> SageMakerModelNested:
    """Convert flat SageMakerModel to nested format."""
    attrs = SageMakerModelAttributes()
    _populate_sage_maker_model_attrs(attrs, sage_maker_model)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sage_maker_model,
        _SAGE_MAKER_MODEL_REL_FIELDS,
        SageMakerModelRelationshipAttributes,
    )
    return SageMakerModelNested(
        guid=sage_maker_model.guid,
        type_name=sage_maker_model.type_name,
        status=sage_maker_model.status,
        version=sage_maker_model.version,
        create_time=sage_maker_model.create_time,
        update_time=sage_maker_model.update_time,
        created_by=sage_maker_model.created_by,
        updated_by=sage_maker_model.updated_by,
        classifications=sage_maker_model.classifications,
        classification_names=sage_maker_model.classification_names,
        meanings=sage_maker_model.meanings,
        labels=sage_maker_model.labels,
        business_attributes=sage_maker_model.business_attributes,
        custom_attributes=sage_maker_model.custom_attributes,
        pending_tasks=sage_maker_model.pending_tasks,
        proxy=sage_maker_model.proxy,
        is_incomplete=sage_maker_model.is_incomplete,
        provenance_type=sage_maker_model.provenance_type,
        home_id=sage_maker_model.home_id,
        depth=sage_maker_model.depth,
        immediate_upstream=sage_maker_model.immediate_upstream,
        immediate_downstream=sage_maker_model.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sage_maker_model_from_nested(nested: SageMakerModelNested) -> SageMakerModel:
    """Convert nested format to flat SageMakerModel."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SageMakerModelAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAGE_MAKER_MODEL_REL_FIELDS,
        SageMakerModelRelationshipAttributes,
    )
    return SageMakerModel(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_sage_maker_model_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sage_maker_model_to_nested_bytes(
    sage_maker_model: SageMakerModel, serde: Serde
) -> bytes:
    """Convert flat SageMakerModel to nested JSON bytes."""
    return serde.encode(_sage_maker_model_to_nested(sage_maker_model))


def _sage_maker_model_from_nested_bytes(data: bytes, serde: Serde) -> SageMakerModel:
    """Convert nested JSON bytes to flat SageMakerModel."""
    nested = serde.decode(data, SageMakerModelNested)
    return _sage_maker_model_from_nested(nested)


